<template>
  <div class="inner-banner blog">
    <div class="container">
      <div class="row">
        <div class="col-sm-12">
          <div class="content">
            <h1>OFERTAS ACADÉMICAS QUE DISPONE ACTUALMENTE LA CARRERA.</h1>
          </div>

          <h4>
                  <router-link to="/">INICIO</router-link>
                </h4>
               
                <h3>OFERTAS ACADÉMICAS</h3>


              
        </div>
      </div>
    </div>
  </div>

  <div class="container blog-wrapper padding-lg">
    <div class="row">
      <div class="col-sm-8 blog-left">
        <div v-if="Ofertas.length == 0" class="col-12 justify-content-center">
          <h2>NO HAY OFERTAS ACADÉMICAS</h2>
        </div>
        <ul class="row news-listing">
          <li
            v-for="(ofer, id_ofer) of Ofertas"
            :key="id_ofer"
            class="col-xs-6 col-sm-6 grid-item"
          >
            <div class="inner">
              <!-- <router-link :to="'/detalleConvocatoria/' + conv.idconvocatorias" @click="$store.commit('clickLink')">
                <div class="image-container">
                  <img :src="url_api + '/Convocatorias/' + conv.con_foto_portada" class="img-responsive" alt="" />
                </div>
              </router-link> -->

              <router-link
                :to="'/detalleOferta/' + ofer.ofertas_id"
                @click="$store.commit('clickLink')"
              >
                <img
                  :src="
                    url_api +
                    '/Carrera/OfertasAcademicas/' +
                    ofer.ofertas_imagen
                  "
                  class="img-responsive"
                  alt=""
                  width="300"
                />
              </router-link>
              <div class="cnt-block">
                <ul class="post-detail">
                  <li>
                    <span class="icon-date-icon ico"></span>
                    <span class="bold">Inscripciones hasta el: </span>
                    {{ dmy(ofer.ofertas_inscripciones_fin) }}
                  </li>
                  <!-- <li>
                    <span class="icon-date-icon ico"></span>
                    <span class="bold">Final: </span> {{ dmy(conv.con_fecha_fin) }}
                  </li> -->
                </ul>
                <h2>
                  <!-- <router-link
                        :to="'/detalleOferta/' + ofer.ofertas_id"
                        @click="$store.commit('clickLink')"
                      > -->
                  {{ ofer.ofertas_titulo }}
                  <!-- </router-link> -->
                </h2>
                <!-- <p>Lorem Ipsum is simply dummy text of the printing and typesetting industry. Lorem Ipsum has been the
                  industry's standard dummy</p> -->

                <!-- <router-link :to="'/detalleConvocatoria/' + conv.idconvocatorias" @click="$store.commit('clickLink')"
                  class="read-more">
                  <span class="icon-play-icon"></span>Leer más
                </router-link> -->

                <h2>
                  <router-link
                    :to="'/detalleOferta/' + ofer.ofertas_id"
                    @click="$store.commit('clickLink')"
                    class="read-more"
                  >
                    <span class="icon-play-icon"></span>Leer más
                  </router-link>
                </h2>
              </div>
            </div>
          </li>
        </ul>

        <div class="text-center">
          <ul class="pagination blue">
            <li class="pagination-arrow disable">
              <a
                href="#"
                aria-label="Previous"
                @click.prevent="pag != 1 ? (pag -= 1) : ''"
              >
                <span aria-hidden="true">
                  <i class="fa fa-angle-left" aria-hidden="true"> </i>
                </span>
              </a>
            </li>

            <li v-for="(i, index) of pager" :key="index">
              <a
                href="#"
                :class="[i == pag ? 'active' : '']"
                @click.prevent="pag = i"
              >
                {{ i }}
              </a>
            </li>

            <li>
              <a
                href="#"
                aria-label="Next"
                @click.prevent="pag != pager ? (pag += 1) : ''"
              >
                <span aria-hidden="true">
                  <i class="fa fa-angle-right" aria-hidden="true"> </i>
                </span>
              </a>
            </li>
          </ul>
        </div>
      </div>

      <!-- Start Right Column -->
      <div class="col-sm-4">
        <SidebarCustom></SidebarCustom>
      </div>
      <!-- End Right Column -->
    </div>
  </div>
</template>

<style scoped>
.bg-overlay-img {
  background-image: url("@/assets/Fondo2.jpg");
}
</style>

<script>
// import HeaderCustom from "@/components/HeaderCustom.vue";
import SidebarCustom from "@/components/SidebarCustom.vue";
import { mapState } from "vuex";
export default {
  name: "OfertasView",
  data() {
    return {
      Ofertas: [],
      search: "",
      searchGet: false,
      searchValues: [],

      NUM_RESULTS: 4,
      pag: 1,
      pager: 0,

      //------
      tipo: "",
      Convocatorias: [],
    };
  },
  computed: {
    ...mapState(["url_api", "getter"]), //===getter
  },
  components: {
    // HeaderCustom,
    SidebarCustom,
  },
  methods: {
    async getOfertasAll() {
      try {
        let res = await this.axios.get(
          "/api/OfertasAcademicasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Ofertas = res.data;
        this.pager = this.Ofertas.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    async getTipoConv(tipo_conv) {
      //===
      try {
        let res = await this.axios.get("/api/Tipoconvocatorias/" + tipo_conv);
        this.tipo = res.data.Descripcion.tipo_conv_comun_titulo;
        this.getConvocatorias();
      } catch (error) {
        console.log(error);
      }
    },
    async getConvocatorias() {
      //===
      try {
        let res = await this.axios.get(
          "/api/convocatoriasAll/" + process.env.VUE_APP_ID_CARRERA
        );
        this.Convocatorias = [];
        res.data.forEach((cca) => {
          if (
            cca.con_estado == "1" &&
            cca.tipo_conv_comun.tipo_conv_comun_titulo == this.tipo
          ) {
            this.Convocatorias.push(cca);
          }
        });
        this.pager = this.Convocatorias.length / this.NUM_RESULTS;
        if (this.pager - Math.trunc(this.pager) > 0) {
          this.pager = Math.trunc(this.pager) + 1;
        }
        this.$store.commit("loading");
      } catch (error) {
        console.log(error);
      }
    },
    clickBack() {
      //===
      this.$store.commit("clickLink");
      this.$router.go(-1);
    },
    dmy(fecha) {
      const meses = [
        "enero",
        "febrero",
        "marzo",
        "abril",
        "mayo",
        "junio",
        "julio",
        "agosto",
        "septiembre",
        "octubre",
        "noviembre",
        "diciembre",
      ];
      let fechaCadena = fecha.substr(0, 10);
      let fechaArray = fechaCadena.split("-");
      return (
        fechaArray[2] +
        " de " +
        meses[parseInt(fechaArray[1]) - 1] +
        " de " +
        fechaArray[0]
      );
    },
    buscar() {
      if (this.search != "") {
        this.searchGet = true;

        this.searchValues = [];
        this.Ofertas.forEach((ofer) => {
          if (
            ofer.ofertas_titulo
              .toUpperCase()
              .includes(this.search.toUpperCase())
          ) {
            this.searchValues.push(ofer);
          }
        });
      } else {
        this.searchGet = false;
      }
    },
  },
  mounted() {
    this.$store.commit("loadOn");
    this.getOfertasAll();

    //=====
    this.getTipoConv(this.$route.params.tipo_conv);
  },
  created() {
    this.$store.commit("loadOn");
    this.getOfertasAll();

    this.getTipoConv(this.$route.params.tipo_conv); //=======
  },
};
</script>
